module signal_converter(
    input [3:0] in_sig,
    output reg [1:0] output_signal
);

always @(*) begin
    if (in_sig < 4) begin
        output_signal = 2'b00;
    end else if (in_sig < 8) begin
        output_signal = 2'b01;
    end else if (in_sig < 12) begin
        output_signal = 2'b10;
    end else begin
        output_signal = 2'b11;
    end
end

endmodule
